import{_ as e,o,c as t,d as a}from"./app.22d6dd61.js";const g=JSON.parse('{"title":"Peer Configuration","description":"","frontmatter":{},"headers":[{"level":2,"title":"Trusted Peers","slug":"trusted-peers"},{"level":2,"title":"Kura","slug":"kura"},{"level":2,"title":"Iroha Public Addresses","slug":"iroha-public-addresses"},{"level":3,"title":"API_URL","slug":"api-url"},{"level":3,"title":"P2P_ADDR","slug":"p2p-addr"},{"level":3,"title":"TELEMETRY_URL","slug":"telemetry-url"},{"level":2,"title":"Logger","slug":"logger"},{"level":3,"title":"MAX_LOG_LEVEL","slug":"max-log-level"},{"level":3,"title":"LOG_FILE_PATH","slug":"log-file-path"}],"relativePath":"guide/configure/peer-configuration.md","lastUpdated":1659428266000}'),r={name:"guide/configure/peer-configuration.md"},i=a('<h1 id="peer-configuration" tabindex="-1">Peer Configuration <a class="header-anchor" href="#peer-configuration" aria-hidden="true">#</a></h1><p>The peer configuration file (<code>/configs/peer/config.json</code>) determines how your blockchain operates.</p><p>Let&#39;s take a closer look at the configurations you&#39;ll work with when you create a network: <code>TRUSTED_PEERS</code>, <code>KURA</code>, <code>TORII</code>, and <code>LOGGER</code>. We&#39;ll cover the <code>PUBLIC_KEY</code> and <code>PRIVATE_KEY</code> later when we talk about <a href="./keys.html">public key cryptography</a>.</p><p>The remaining options are for fine-tuning Iroha, so you don&#39;t need to worry about them at this stage. Once you are familiar with the necessary basics, check <a href="https://github.com/hyperledger/iroha/blob/iroha2-dev/docs/source/references/config.md" target="_blank" rel="noopener noreferrer">Iroha Configuration Reference</a> for more details and all available options.</p><h2 id="trusted-peers" tabindex="-1">Trusted Peers <a class="header-anchor" href="#trusted-peers" aria-hidden="true">#</a></h2><p>Iroha is a blockchain ledger. In order for it to work optimally and be Byzantine-fault tolerant with the maximum number of faults allowed, it needs to be started with a set number of peers: <code>4</code>, <code>7</code>, <code>10</code>, ... <code>3f+1</code>, where <code>f</code> is the allowed number of faults.</p><p>So usually, when you want to start an Iroha deployment, you should already know a number of peers that you can trust and join their blockchain. The way it works in the examples is that you just specify in four <code>config.json</code> files four peers with their public keys and API addresses.</p><p>Since Iroha has no automatic peer discovery, the only other way to make peers known to each other is to use the <code>iroha_client_cli</code> to register new peers. This is not too difficult with the provided client libraries. With Python&#39;s Beautiful Soup, the curated list of peers can be updated, registered, and un-registered on its own.</p><h2 id="kura" tabindex="-1">Kura <a class="header-anchor" href="#kura" aria-hidden="true">#</a></h2><p>KURA is the &quot;warehouse&quot; engine of Iroha. The <code>BLOCK_STORE_PATH</code> specifies where the blocks are stored. You can change it to a custom location if for some reason the default location (<code>./blocks</code>) is not available or desirable.</p><p>For more details, check <a href="https://github.com/hyperledger/iroha/blob/iroha2-dev/docs/source/references/config.md#kura" target="_blank" rel="noopener noreferrer"><code>KURA</code> configuration reference</a>.</p><h2 id="iroha-public-addresses" tabindex="-1">Iroha Public Addresses <a class="header-anchor" href="#iroha-public-addresses" aria-hidden="true">#</a></h2><p><code>TORII</code> is the module in charge of handling incoming and outgoing connections.</p><p>Here we only cover the <code>API_URL</code>, <code>P2P_ADDR</code>, and <code>TELEMETRY_URL</code> configurations. On Github you&#39;ll find <a href="https://github.com/hyperledger/iroha/blob/iroha2-dev/docs/source/references/config.md#torii" target="_blank" rel="noopener noreferrer">the detailed reference for <code>TORII</code></a>.</p><h3 id="api-url" tabindex="-1"><code>API_URL</code> <a class="header-anchor" href="#api-url" aria-hidden="true">#</a></h3><p>The <code>API_URL</code> is the location to which the client(s) make their requests. You can also use it to change some peer-specific configuration options.</p><p>Most of the time, the only reason to change the <code>API_URL</code> is to change the port, in case <code>8080</code> is either closed, or if you want to randomise ports to avoid certain kinds of attacks.</p><h3 id="p2p-addr" tabindex="-1"><code>P2P_ADDR</code> <a class="header-anchor" href="#p2p-addr" aria-hidden="true">#</a></h3><p>The <code>P2P_ADDR</code> is the internal address used for communication between peers. This address should be included in the <code>TRUSTED_PEERS</code> section of the configuration file.</p><h3 id="telemetry-url" tabindex="-1"><code>TELEMETRY_URL</code> <a class="header-anchor" href="#telemetry-url" aria-hidden="true">#</a></h3><p>The <code>TELEMETRY_URL</code> is used to specify the prometheus endpoint address. It&#39;s set by adding <code>&quot;TELEMETRY_URL&quot;: &quot;127.0.0.1:8180&quot;</code> to the <code>TORII</code> section of the configuration file.</p><p>It&#39;s not meant to be human-readable. However, a <code>GET</code> request to the <code>127.0.0.1:8180/status</code> will give you a JSON-encoded representation of the top-level metrics, while a <code>GET</code> request to <code>127.0.0.1:8180/metrics</code> will give you a (somewhat verbose) list of all available metrics gathered in Iroha. You might want to change this if you&#39;re having trouble gathering metrics using <code>prometheus</code>.</p><h2 id="logger" tabindex="-1">Logger <a class="header-anchor" href="#logger" aria-hidden="true">#</a></h2><p>Let&#39;s cover the most useful <code>LOGGER</code> configurations, <code>MAX_LOG_LEVEL</code> and <code>LOG_FILE_PATH</code>.</p><h3 id="max-log-level" tabindex="-1"><code>MAX_LOG_LEVEL</code> <a class="header-anchor" href="#max-log-level" aria-hidden="true">#</a></h3><p>The <code>MAX_LOG_LEVEL</code> is used to determine which messages are logged.</p><p>With <code>&quot;MAX_LOG_LEVEL&quot;: &quot;WARN&quot;</code> you won&#39;t get any messages unless they are either a warning or an error. Beside <code>WARN</code>, other available options are:</p><ul><li><code>TRACE</code> (log every time you enter a function)</li><li><code>DEBUG</code> (use when you know something went wrong)</li><li><code>INFO</code> (the default)</li><li><code>WARN</code> (log everything that could be an error)</li><li><code>ERROR</code> (to silence any logging except for error messages)</li></ul><h3 id="log-file-path" tabindex="-1"><code>LOG_FILE_PATH</code> <a class="header-anchor" href="#log-file-path" aria-hidden="true">#</a></h3><p>Another useful option is <code>&quot;LOG_FILE_PATH&quot;: bunyan.json</code>. It creates (if it didn&#39;t already exist) a file called <code>bunyan.json</code> that contains the message log in a structured format.</p><p>This is extremely useful for two reasons. Firstly, you can use the <code>bunyan</code> log viewer to filter information more precisely than Iroha would allow you to do. Do you only want messages from a specific module or package? You can do that with <code>bunyan</code>. Secondly, while copying logs is not too big of a problem if your instance is just a small setup, for bigger setups the log will be larger. Having it saved to a file makes much more sense in that case.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>You can also set <code>LOG_FILE_PATH</code> to <code>/dev/stdout</code> if you want to use bunyan&#39;s logging facilities directly without saving the output.</p></div>',32),d=[i];function c(s,n,l,h,u,p){return o(),t("div",null,d)}var m=e(r,[["render",c]]);export{g as __pageData,m as default};
